import psycopg2
from psycopg2 import sql


class UserRepository:
    def __init__(self, connection):
        self.connection = connection

    def search_users(self, username=None, email=None, role=None, status=None):
        conditions = []
        params = []

        if username is not None:
            conditions.append(sql.SQL("username ILIKE %s"))
            params.append(f"%{username}%")

        if email is not None:
            conditions.append(sql.SQL("email ILIKE %s"))
            params.append(f"%{email}%")

        if role is not None:
            conditions.append(sql.SQL("role = %s"))
            params.append(role)

        if status is not None:
            conditions.append(sql.SQL("status = %s"))
            params.append(status)

        query = sql.SQL("SELECT id, username, email, role, status FROM users")
        if conditions:
            query += sql.SQL(" WHERE ") + sql.SQL(" AND ").join(conditions)
        query += sql.SQL(" ORDER BY username ASC")

        with self.connection.cursor() as cursor:
            cursor.execute(query, params)
            rows = cursor.fetchall()

        return [
            {
                "id": row[0],
                "username": row[1],
                "email": row[2],
                "role": row[3],
                "status": row[4],
            }
            for row in rows
        ]


def get_db_connection(dsn):
    return psycopg2.connect(dsn)


